tabbed-services.js:
const tabs = document.querySelectorAll('.service-tab');
tabs.forEach(tab => {
  tab.addEventListener('click', () => {
    tabs.forEach(t => t.classList.remove('active'));
    document.querySelectorAll('.service-panel').forEach(p => p.classList.remove('active'));
    tab.classList.add('active');
    document.getElementById(tab.dataset.target).classList.add('active');
  });
});

horizontal-scroll-gallery.js:
const gallery = document.querySelector('.h-scroll-gallery');
let isDown = false, startX, scrollLeft;
gallery.addEventListener('mousedown', e => { isDown=true; startX=e.pageX-gallery.offsetLeft; scrollLeft=gallery.scrollLeft; });
gallery.addEventListener('mouseleave', () => isDown=false);
gallery.addEventListener('mouseup', () => isDown=false);
gallery.addEventListener('mousemove', e => { if(!isDown) return; e.preventDefault(); const x=e.pageX-gallery.offsetLeft; gallery.scrollLeft=scrollLeft-(x-startX)*1.5; });

fullscreen-slideshow.js:
let current = 0;
const slides = document.querySelectorAll('.slide');
function goTo(n) {
  slides[current].classList.remove('active');
  current = (n + slides.length) % slides.length;
  slides[current].classList.add('active');
}
document.querySelector('.slide-prev').onclick = () => goTo(current - 1);
document.querySelector('.slide-next').onclick = () => goTo(current + 1);
setInterval(() => goTo(current + 1), 5000);

accordion.js:
document.querySelectorAll('.faq-q').forEach(btn => {
  btn.addEventListener('click', () => {
    const item = btn.closest('.faq-item');
    const isOpen = item.classList.contains('open');
    document.querySelectorAll('.faq-item').forEach(i => { i.classList.remove('open'); i.querySelector('.faq-q').setAttribute('aria-expanded','false'); });
    if (!isOpen) { item.classList.add('open'); btn.setAttribute('aria-expanded','true'); }
  });
});
